// Precio promedio bolsa nacional XM últimos N días.
// XM cambia MetricId y endpoint con frecuencia.
// Estrategia: probar muchos candidatos rápido (8s timeout + 30s budget global)
// y si todos fallan, intentar discovery vía MasterDataMetrics.
const src = $input.first().json;
const body = src.body || src;
const daysBack = Math.min(Math.max(parseInt(body.days ?? 30, 10) || 30, 1), 90);

const XM_BASE = 'https://servapibi.xm.com.co';
const REQUEST_TIMEOUT_MS = 8000;
const GLOBAL_BUDGET_MS = 30000;
const startedAt = Date.now();
const isoDate = d => d.toISOString().slice(0, 10);
const endDate = new Date(Date.now() - 24 * 60 * 60 * 1000); // T-1 (XM publica con delay)
const startDate = new Date(endDate.getTime() - daysBack * 24 * 60 * 60 * 1000);

// XM a veces responde con texto plano en vez de JSON (ej. 'Id de Métrica no encontrada.')
// Devolvemos un objeto marker para no crashear y poder seguir con el siguiente candidato.
const safeParse = (raw) => {
  if (raw == null) return { __plainText: '' };
  if (typeof raw === 'object') return raw;
  const s = String(raw).trim();
  if (!s) return { __plainText: '' };
  if (s[0] !== '{' && s[0] !== '[') return { __plainText: s };
  try { return JSON.parse(s); } catch { return { __plainText: s }; }
};

const postXM = async (path, reqBody) => {
  const r = await this.helpers.httpRequest({
    method: 'POST',
    url: `${XM_BASE}${path}`,
    headers: { 'Content-Type': 'application/json', 'Accept': 'application/json', 'User-Agent': 'alebas-cotizador/1.0' },
    body: JSON.stringify(reqBody),
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
    timeout: REQUEST_TIMEOUT_MS,
  });
  return { status: r.statusCode, body: safeParse(r.body) };
};

const getXM = async (path) => {
  const r = await this.helpers.httpRequest({
    method: 'GET',
    url: `${XM_BASE}${path}`,
    headers: { 'Accept': 'application/json', 'User-Agent': 'alebas-cotizador/1.0' },
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
    timeout: REQUEST_TIMEOUT_MS,
  });
  return { status: r.statusCode, body: safeParse(r.body) };
};

// Considera respuesta válida si: 2xx + body es objeto/array + NO es marker de texto plano + NO es mensaje de error conocido.
const KNOWN_ERROR_TEXTS = [
  'id de métrica no encontrada',
  'metrica no encontrada',
  'metric not found',
  'no encontrado',
  'error',
];
const isValidPayload = (resp) => {
  if (!resp || resp.status < 200 || resp.status >= 300) return false;
  const b = resp.body;
  if (!b || typeof b !== 'object') return false;
  if ('__plainText' in b) {
    const t = String(b.__plainText).toLowerCase();
    return !KNOWN_ERROR_TEXTS.some(e => t.includes(e));
  }
  return true;
};

// Candidatos: combinación de paths × MetricIds × Entities. Como las requests son rápidas (~1s),
// podemos probar varios sin cuelgues largos.
const PATHS = ['/hourly', '/daily', '/HourlyMetrics', '/DailyMetrics'];
const METRIC_IDS = ['PrecBolsNal', 'Preciobols', 'PrecBolsa', 'PrecioBolsaNal', 'PrecioBolsa', 'Bolsa', 'Precbolsanal'];
const ENTITIES = ['Sistema', 'SIN', null];
const CANDIDATES = [];
for (const path of PATHS) {
  for (const MetricId of METRIC_IDS) {
    for (const Entity of ENTITIES) {
      CANDIDATES.push({ path, MetricId, Entity });
    }
  }
}

let rawJson = null;
let usedLabel = '';
const tried = [];
let lastError = '';
for (const c of CANDIDATES) {
  if (Date.now() - startedAt > GLOBAL_BUDGET_MS) {
    lastError = `global timeout (${GLOBAL_BUDGET_MS}ms) excedido`;
    break;
  }
  const reqBody = { MetricId: c.MetricId, StartDate: isoDate(startDate), EndDate: isoDate(endDate) };
  if (c.Entity) reqBody.Entity = c.Entity;
  const label = `${c.path}/${c.MetricId}${c.Entity ? '/'+c.Entity : ''}`;
  try {
    const resp = await postXM(c.path, reqBody);
    tried.push({ label, status: resp.status, hint: resp.body?.__plainText?.slice(0, 80) });
    if (isValidPayload(resp)) {
      rawJson = resp.body;
      usedLabel = label;
      break;
    }
  } catch (err) {
    lastError = err.message;
    tried.push({ label, error: err.message });
  }
}

// Discovery fallback: si nada respondió con datos, listar métricas disponibles
// para que en el siguiente deploy actualicemos el array METRIC_IDS.
let discovery = null;
if (!rawJson && Date.now() - startedAt < GLOBAL_BUDGET_MS - 3000) {
  try {
    const resp = await getXM('/MasterDataMetrics');
    if (resp.status >= 200 && resp.status < 300 && resp.body && typeof resp.body === 'object' && !('__plainText' in resp.body)) {
      discovery = Array.isArray(resp.body) ? resp.body.slice(0, 100) : resp.body;
    }
  } catch (err) {
    // ignore
  }
}

if (!rawJson) {
  return [{ json: { ok: false, reason: 'xm_schema_drift', detail: `Ningún MetricId respondió con datos válidos. ${lastError ? 'Último error: ' + lastError : ''}`, tried, discovery, elapsedMs: Date.now() - startedAt } }];
}

// Extractor recursivo: recoge valores numéricos en claves Hour##/Hora##/Value##/Precio/Price/Total.
const values = [];
const walk = (node) => {
  if (node == null) return;
  if (Array.isArray(node)) { node.forEach(walk); return; }
  if (typeof node === 'object') {
    for (const [k, v] of Object.entries(node)) {
      if (/^(Hour|Hora|Value|Precio|Price|Total)\d{0,2}$/i.test(k) && Number.isFinite(Number(v)) && Number(v) > 0) {
        values.push(Number(v));
      } else if (typeof v === 'object') {
        walk(v);
      }
    }
  }
};
walk(rawJson);

if (!values.length) {
  return [{ json: { ok: false, reason: 'xm_no_values', detail: `Respuesta válida pero sin valores numéricos extraíbles (métrica: ${usedLabel})`, sample: rawJson } }];
}

const avgMwh = values.reduce((s, v) => s + v, 0) / values.length;
return [{ json: {
  ok: true,
  cop_per_kwh:     Number((avgMwh / 1000).toFixed(2)),
  avg_cop_per_mwh: Number(avgMwh.toFixed(2)),
  samples:         values.length,
  periodDays:      daysBack,
  startDate:       isoDate(startDate),
  endDate:         isoDate(endDate),
  usedMetric:      usedLabel,
  syncedAt:        new Date().toISOString(),
  source:          `XM ${usedLabel}`,
} }];
